from zeep import Client
import getpass

def main():
    # Initialize client with third party insurance service WSDL
    client = Client('https://thirdpartyinsuranceservice?wsdl')
    
    while True:
        policy_number = input("Enter the policy number (or 'q' to quit): ")
        if policy_number.lower() == 'q':
            break
        
        customer_name = getpass.getpass("Enter the customer name: ")  # Hide sensitive data like passwords
    
        # Call third party insurance service operation with provided inputs
        result = client.service.OperationName(policy_number, customer_name)

        print("\nResult:\n", result)

if __name__ == "__main__":
    main()